use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, InlineDatum}
use cardano/address.{Script, Credential}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type SynthMintConfig {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  vault_script_hash: ByteArray,
  collateral_ratio: Int,
  max_staleness_ms: Int,
}

pub type MintAction {
  MintSynth { ada_collateral_lovelaces: Int, synth_amount: Int }
  BurnSynth
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn output_to_vault(
  outputs: List<Output>,
  vault_hash: ByteArray,
  min_lovelaces: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        Script(hash) ->
          hash == vault_hash && assets.lovelace_of(o.value) >= min_lovelaces
        _ -> False
      }
    },
  )
}

validator collateralized_synth_mint(config: SynthMintConfig) {
  mint(redeemer: Data, _policy_id: PolicyId, self: Transaction) {
    expect action: MintAction = redeemer
    let oracle =
      get_oracle_datum(
        config.oracle_policy,
        config.oracle_asset,
        self.reference_inputs,
      )

    // Staleness check
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < config.max_staleness_ms

    when action is {
      MintSynth { ada_collateral_lovelaces, synth_amount } -> {
        // Compute USD value of the collateral
        let collateral_usd =
          compute_value(ada_collateral_lovelaces, oracle.price, oracle.exponent)

        // Required collateral = synth_amount * collateral_ratio / 100
        let required_collateral_usd =
          synth_amount * config.collateral_ratio / 100

        // Collateral must exceed required amount
        let ratio_ok = collateral_usd >= required_collateral_usd

        // Verify ADA is sent to vault
        let vault_ok =
          output_to_vault(
            self.outputs,
            config.vault_script_hash,
            ada_collateral_lovelaces,
          )

        is_fresh && ratio_ok && vault_ok
      }
      BurnSynth -> is_fresh
    }
  }

  else(_) {
    fail
  }
}

