use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type LoanDatum {
  borrower: ByteArray,
  debt_micro_usd: Int,
  ada_locked_lovelaces: Int,
}

pub type LoanAction {
  Repay
  Liquidate
}

pub type LiquidationConfig {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  min_health_ratio: Int,
  max_staleness_ms: Int,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

/// Calcula el ratio de salud como porcentaje entero.
/// health_ratio = (valor_usd_del_colateral * 100) / deuda
fn health_ratio(
  ada_locked_lovelaces: Int,
  debt_micro_usd: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_usd =
    compute_value(ada_locked_lovelaces, raw_price, exponent)
  collateral_usd * 100 / debt_micro_usd
}

validator liquidacion_prestamo(config: LiquidationConfig) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(raw_datum) = datum
    expect loan: LoanDatum = raw_datum
    expect action: LoanAction = redeemer

    let oracle =
      get_oracle_datum(
        config.oracle_policy,
        config.oracle_asset,
        self.reference_inputs,
      )

    // Verificación de frescura
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let es_fresco = upper - oracle.timestamp < config.max_staleness_ms

    when action is {
      Repay -> {
        // Solo el prestatario puede pagar
        let firmado =
          list.has(self.extra_signatories, loan.borrower)
        es_fresco && firmado
      }
      Liquidate -> {
        // Calcular el ratio de salud actual
        let ratio_actual =
          health_ratio(
            loan.ada_locked_lovelaces,
            loan.debt_micro_usd,
            oracle.price,
            oracle.exponent,
          )

        // Solo liquidar si el ratio está por debajo del mínimo
        let sub_colateralizado = ratio_actual < config.min_health_ratio

        es_fresco && sub_colateralizado
      }
    }
  }

  else(_) {
    fail
  }
}

