test health_ratio_150_porciento() {
  // 1.5 ADA a $0.70 = $1.05 micro-USD = 1_050_000
  // deuda = 700_000 micro-USD
  // ratio = 1_050_000 * 100 / 700_000 = 150
  health_ratio(1_500_000, 700_000, 70_000_000, -8) == 150
}

test health_ratio_100_porciento() {
  // 1.0 ADA a $0.70 = 700_000 micro-USD
  // deuda = 700_000 → ratio = 100
  health_ratio(1_000_000, 700_000, 70_000_000, -8) == 100
}

test health_ratio_sub_colateralizado() {
  // 0.5 ADA a $0.70 = 350_000 micro-USD
  // deuda = 700_000 → ratio = 50 < 110
  health_ratio(500_000, 700_000, 70_000_000, -8) < 110
}

test health_ratio_deuda_cero_falla() fail {
  health_ratio(1_000_000, 0, 70_000_000, -8) == 0
}

use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type SellOrderDatum {
  owner: ByteArray,
  min_sell_price: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator sell_order {
  spend(
    datum_opt: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect datum: SellOrderDatum = raw_datum
    let oracle =
      get_oracle_datum(
        datum.oracle_policy,
        datum.oracle_asset,
        self.reference_inputs,
      )
    // Staleness check: oracle must be fresh within 5 minutes (300_000 ms)
    let max_age_ms = 300_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms
    expect is_fresh
    // Price check: oracle price must be at or above the min sell price
    // min_sell_price is in the same raw units as oracle price (e.g. micro-USD per ADA)
    let price_ok = oracle.price >= datum.min_sell_price
    expect price_ok
    // Owner must sign
    let owner_signed =
      list.has(self.extra_signatories, datum.owner)
    owner_signed
  }
}

