validator orden_venta_limite {
  spend(
    datum_opt: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect datum: OrdenVentaDatum = raw_datum
    let oracle =
      get_oracle_datum(
        datum.oracle_policy,
        datum.oracle_asset,
        self.reference_inputs,
      )
    // Verificación de frescura: máximo 4 minutos (240_000 ms)
    let max_age_ms = 240_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let es_reciente = upper - oracle.timestamp < max_age_ms
    expect es_reciente
    // Verificación de precio máximo: el precio actual no debe superar el máximo
    // Esto protege al vendedor de ejecutar la orden cuando el precio ya cayó
    // y asegura que solo se ejecute cuando el precio está en un rango aceptable
    let precio_ok = oracle.price <= datum.precio_maximo
    expect precio_ok
    // El propietario debe firmar la transacción
    list.has(self.extra_signatories, datum.propietario)
  }
}

