use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type PrestamoDatum {
  propietario: ByteArray,
  ada_bloqueados: Int,
  deuda_synth: Int,
  ratio_minimo: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

pub type AccionPrestamo {
  Liquidar
  Retirar
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn health_ratio(
  ada_lovelaces: Int,
  deuda_synth: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let valor_colateral = compute_value(ada_lovelaces, raw_price, exponent)
  valor_colateral * 100 / deuda_synth
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator prestamo_colateral {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect prestamo: PrestamoDatum = raw_datum
    expect accion: AccionPrestamo = redeemer
    let oracle =
      get_oracle_datum(
        prestamo.oracle_policy,
        prestamo.oracle_asset,
        self.reference_inputs,
      )
    // Verificación de frescura: máximo 2 minutos (120_000 ms)
    let max_age_ms = 120_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let es_reciente = upper - oracle.timestamp < max_age_ms
    expect es_reciente
    // Calcular ratio de salud
    let ratio =
      health_ratio(
        prestamo.ada_bloqueados,
        prestamo.deuda_synth,
        oracle.price,
        oracle.exponent,
      )
    when accion is {
      Liquidar -> {
        // Cualquiera puede liquidar si el colateral cae por debajo del ratio mínimo (200%)
        ratio < prestamo.ratio_minimo
      }
      Retirar -> {
        // Solo el propietario puede retirar, y el colateral debe estar por encima del mínimo
        let es_propietario =
          list.has(self.extra_signatories, prestamo.propietario)
        let colateral_suficiente = ratio >= prestamo.ratio_minimo
        es_propietario && colateral_suficiente
      }
    }
  }
}

