use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Datum de la posición de colateral
/// debt_micro_usd: deuda pendiente en micro-USD
/// min_health_ratio: ratio mínimo de salud (150 = 150%)
pub type SpendDatum {
  owner: VerificationKeyHash,
  threshold_price: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  debt_micro_usd: Int,
  min_health_ratio: Int,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

/// Calcula el ratio de salud como porcentaje entero
/// health = (valor_colateral * 100) / deuda
fn health_ratio(
  ada_lovelaces: Int,
  debt_micro_usd: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_value = compute_value(ada_lovelaces, raw_price, exponent)
  collateral_value * 100 / debt_micro_usd
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator collateral_release {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect spend_datum: SpendDatum = raw_datum

    let oracle_datum =
      get_oracle_datum(
        spend_datum.oracle_policy,
        spend_datum.oracle_asset,
        self.reference_inputs,
      )

    // Verificación de antigüedad: datos del oráculo deben tener menos de 5 minutos
    let max_age_ms = 300_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let oracle_fresh = upper - oracle_datum.timestamp < max_age_ms

    // Encontrar la UTxO que se está gastando para obtener el ADA bloqueado
    expect Some(spent_input) =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })
    let ada_locked = assets.lovelace_of(spent_input.output.value)

    // Calcular ratio de salud de la posición
    let current_health =
      health_ratio(
        ada_locked,
        spend_datum.debt_micro_usd,
        oracle_datum.price,
        oracle_datum.exponent,
      )

    // Solo permitir liberación si la salud está POR ENCIMA del mínimo
    let health_sufficient = current_health >= spend_datum.min_health_ratio

    // El propietario debe firmar la transacción
    let owner_signed =
      list.has(self.extra_signatories, spend_datum.owner)

    oracle_fresh && health_sufficient && owner_signed
  }

  else(_) {
    fail
  }
}

