validator cdp_v1(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  collateral_ratio: Int,
  liquidation_threshold: Int,
  max_staleness_ms: Int,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp_datum: CDPDatum = raw_datum
    expect action: Action = redeemer
    let oracle =
      get_oracle_datum(oracle_policy, oracle_asset, self.reference_inputs)
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_staleness_ms
    expect is_fresh
    when action is {
      Mint -> {
        let ada_in_output =
          list.foldl(
            self.outputs,
            0,
            fn(out, acc) {
              when out.datum is {
                InlineDatum(d) -> {
                  expect new_cdp: CDPDatum = d
                  if new_cdp.owner == cdp_datum.owner {
                    acc + assets.lovelace_of(out.value)
                  } else {
                    acc
                  }
                }
                _ -> acc
              }
            },
          )
        let ada_deposited = ada_in_output - cdp_datum.ada_locked
        let max_mintable =
          compute_value(ada_deposited, oracle.price, oracle.exponent) * 100 / collateral_ratio
        expect ada_deposited >= 1_000_000
        expect max_mintable > 0
        let owner_signed =
          list.has(self.extra_signatories, cdp_datum.owner)
        owner_signed
      }
      Burn -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp_datum.owner)
        expect owner_signed
        cdp_datum.synth_minted > 0
      }
      Liquidate -> {
        let current_health =
          health_ratio(
            cdp_datum.ada_locked,
            cdp_datum.synth_minted,
            oracle.price,
            oracle.exponent,
          )
        current_health < liquidation_threshold
      }
    }
  }
}

