validator cdp_sintetico(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ratio_colateral: Int,
  umbral_liquidacion: Int,
  max_antiguedad_ms: Int,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp: DatoCDP = raw_datum
    expect accion: Accion = redeemer
    let oracle =
      obtener_dato_oracle(oracle_policy, oracle_asset, self.reference_inputs)
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let dato_fresco = upper - oracle.timestamp < max_antiguedad_ms
    expect dato_fresco
    when accion is {
      Mint -> {
        let total_ada_salida =
          list.foldl(
            self.outputs,
            0,
            fn(salida, acc) {
              when salida.datum is {
                InlineDatum(d) -> {
                  expect nuevo_cdp: DatoCDP = d
                  if nuevo_cdp.propietario == cdp.propietario {
                    acc + assets.lovelace_of(salida.value)
                  } else {
                    acc
                  }
                }
                _ -> acc
              }
            },
          )
        let ada_depositado = total_ada_salida - cdp.ada_bloqueado
        expect ada_depositado >= 1_000_000
        let valor_usd =
          compute_value(ada_depositado, oracle.price, oracle.exponent)
