      }
      Burn -> {
        let firma_propietario =
          list.has(self.extra_signatories, cdp.propietario)
        expect firma_propietario
        cdp.synth_acunado > 0
      }
      Liquidate -> {
        let salud_actual =
          health_ratio(
            cdp.ada_bloqueado,
            cdp.synth_acunado,
            oracle.price,
            oracle.exponent,
          )
        salud_actual < umbral_liquidacion
      }
    }
  }
}

