fn find_script_outputs(
  outputs: List<Output>,
  script_hash: ByteArray,
) -> List<Output> {
  list.filter(
    outputs,
    fn(out) {
      when out.address.payment_credential is {
        Script(h) -> h == script_hash
        _ -> False
      }
    },
  )
}

validator cdp_advanced(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  collateral_ratio: Int,
  liquidation_threshold: Int,
  max_staleness_ms: Int,
  cdp_script_hash: ByteArray,
  synth_asset_name: AssetName,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp: CDPDatum = raw_datum
    expect action: Action = redeemer
    let oracle =
      get_oracle_datum(oracle_policy, oracle_asset, self.reference_inputs)
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    expect upper - oracle.timestamp < max_staleness_ms
    when action is {
      Mint -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp.owner)
        expect owner_signed
        let continuation_outputs =
          find_script_outputs(self.outputs, cdp_script_hash)
        expect Some(cont_output) = list.head(continuation_outputs)
        expect InlineDatum(cont_raw) = cont_output.datum
        expect new_cdp: CDPDatum = cont_raw
        expect new_cdp.owner == cdp.owner
        let new_ada = assets.lovelace_of(cont_output.value)
        expect new_ada > cdp.ada_locked
        let ada_added = new_ada - cdp.ada_locked
        expect ada_added >= 1_000_000
        let new_synth_value =
          compute_value(new_ada, oracle.price, oracle.exponent)
        let max_synth = new_synth_value * 100 / collateral_ratio
        new_cdp.synth_minted <= max_synth && new_cdp.synth_minted > 0
      }
      Burn -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp.owner)
        expect owner_signed
        expect cdp.synth_minted > 0
        let synth_burned =
          assets.quantity_of(self.mint, cdp_script_hash, synth_asset_name)
        synth_burned < 0
      }
      Liquidate -> {
        expect cdp.synth_minted > 0
        let current_health =
          health_ratio(
            cdp.ada_locked,
            cdp.synth_minted,
            oracle.price,
            oracle.exponent,
          )
        expect current_health < liquidation_threshold
        let synth_burned =
          assets.quantity_of(self.mint, cdp_script_hash, synth_asset_name)
        synth_burned < 0
      }
    }
  }

  mint(
    _redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let script_inputs =
      list.filter(
        self.inputs,
        fn(inp) {
          when inp.output.address.payment_credential is {
            Script(h) -> h == cdp_script_hash
            _ -> False
          }
        },
      )
    list.length(script_inputs) >= 1
  }
}

