        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = entrada_oracle.output.datum
  expect dato: DatoOracle = raw
  dato
}

fn outputs_del_script(
  outputs: List<Output>,
  hash_script: ByteArray,
) -> List<Output> {
  list.filter(
    outputs,
    fn(out) {
      when out.address.payment_credential is {
        Script(h) -> h == hash_script
        _ -> False
      }
    },
  )
}

fn contar_inputs_script(
  inputs: List<Input>,
  hash_script: ByteArray,
) -> Int {
  list.foldl(
    inputs,
    0,
    fn(inp, acc) {
      when inp.output.address.payment_credential is {
        Script(h) ->
          if h == hash_script {
            acc + 1
          } else {
            acc
          }
        _ -> acc
      }
    },
  )
}

validator cdp_completo(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ratio_colateral: Int,
  umbral_liquidacion: Int,
  max_antiguedad_ms: Int,
  hash_script_cdp: ByteArray,
  nombre_synth: AssetName,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp: DatoCDP = raw_datum
    expect accion: Accion = redeemer
    let oracle =
      obtener_oracle(oracle_policy, oracle_asset, self.reference_inputs)
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let fresco = upper - oracle.timestamp < max_antiguedad_ms
    expect fresco
    when accion is {
      Mint -> {
        let firmado =
          list.has(self.extra_signatories, cdp.propietario)
        expect firmado
        let salidas_script =
          outputs_del_script(self.outputs, hash_script_cdp)
        expect Some(salida_cont) = list.head(salidas_script)
        expect InlineDatum(raw_cont) = salida_cont.datum
        expect nuevo_cdp: DatoCDP = raw_cont
        expect nuevo_cdp.propietario == cdp.propietario
        let nuevo_ada = assets.lovelace_of(salida_cont.value)
        expect nuevo_ada > cdp.ada_bloqueado
        let ada_agregado = nuevo_ada - cdp.ada_bloqueado
        expect ada_agregado >= 1_000_000
        let valor_total_usd =
          compute_value(nuevo_ada, oracle.price, oracle.exponent)
        let max_acunable = valor_total_usd * 100 / ratio_colateral
        let ratio_resultante =
          health_ratio(
            nuevo_ada,
            nuevo_cdp.synth_acunado,
            oracle.price,
            oracle.exponent,
          )
        and {
          nuevo_cdp.synth_acunado <= max_acunable,
          nuevo_cdp.synth_acunado > 0,
          ratio_resultante >= ratio_colateral,
        }
      }
      Burn -> {
        let firmado =
          list.has(self.extra_signatories, cdp.propietario)
        expect firmado
        expect cdp.synth_acunado > 0
        let synth_quemado =
          assets.quantity_of(self.mint, hash_script_cdp, nombre_synth)
        expect synth_quemado < 0
        let cantidad_quemada = -synth_quemado
        let salidas_script =
          outputs_del_script(self.outputs, hash_script_cdp)
        when list.head(salidas_script) is {
          Some(salida_cont) -> {
            expect InlineDatum(raw_cont) = salida_cont.datum
            expect nuevo_cdp: DatoCDP = raw_cont
            expect nuevo_cdp.propietario == cdp.propietario
            let synth_restante = cdp.synth_acunado - cantidad_quemada
            expect nuevo_cdp.synth_acunado == synth_restante
            if synth_restante > 0 {
              let nuevo_ada = assets.lovelace_of(salida_cont.value)
              let ratio_resultante =
                health_ratio(
                  nuevo_ada,
                  synth_restante,
                  oracle.price,
                  oracle.exponent,
                )
              ratio_resultante >= ratio_colateral
            } else {
              True
            }
          }
          None -> cantidad_quemada == cdp.synth_acunado
        }
      }
      Liquidate -> {
        expect cdp.synth_acunado > 0
        let salud_actual =
          health_ratio(
            cdp.ada_bloqueado,
            cdp.synth_acunado,
            oracle.price,
            oracle.exponent,
          )
        expect salud_actual < umbral_liquidacion
        let synth_quemado =
          assets.quantity_of(self.mint, hash_script_cdp, nombre_synth)
        synth_quemado < 0
      }
    }
  }

  mint(
    _redeemer: Data,
    _policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let n_inputs_script =
      contar_inputs_script(self.inputs, hash_script_cdp)
    n_inputs_script >= 1
  }
}

