use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type VaultDatum {
  owner: ByteArray,
  min_price: Int,
  min_exponent: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  max_staleness_ms: Int,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn normalize_price(raw_price: Int, exponent: Int) -> Int {
  let abs_exp = if exponent < 0 { -exponent } else { exponent }
  raw_price * 1_000_000 / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator price_gate {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect vault: VaultDatum = raw_datum

    // Owner must sign
    expect list.has(self.extra_signatories, vault.owner)

    // Fetch oracle
    let oracle =
      get_oracle_datum(
        vault.oracle_policy,
        vault.oracle_asset,
        self.reference_inputs,
      )

    // Staleness check
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < vault.max_staleness_ms
    expect is_fresh

    // Normalize both prices to same scale (micro-units) and compare
    let current_normalized = normalize_price(oracle.price, oracle.exponent)
    let min_normalized =
      normalize_price(vault.min_price, vault.min_exponent)

    // Price must exceed the minimum threshold
    current_normalized >= min_normalized
  }

  else(_) {
    fail
  }
}

