pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type MintConfig {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  max_price: Int,
  max_price_exponent: Int,
  max_staleness_ms: Int,
  admin: ByteArray,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp = if exponent < 0 { -exponent } else { exponent }
  lovelaces * raw_price / pow(10, abs_exp)
}

fn price_in_micro(raw_price: Int, exponent: Int) -> Int {
  let abs_exp = if exponent < 0 { -exponent } else { exponent }
  raw_price * 1_000_000 / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator synth_mint(config: MintConfig) {
  mint(_redeemer: Data, _policy_id: PolicyId, self: Transaction) -> Bool {
    // Admin debe firmar
    expect list.has(self.extra_signatories, config.admin)

    // Obtener datos del oráculo
    let oracle =
      get_oracle_datum(
        config.oracle_policy,
        config.oracle_asset,
        self.reference_inputs,
      )

    // Verificar frescura del dato
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < config.max_staleness_ms
    expect is_fresh

    // El precio actual debe ser menor o igual al umbral máximo
    let current_micro = price_in_micro(oracle.price, oracle.exponent)
    let max_micro =
      price_in_micro(config.max_price, config.max_price_exponent)

    current_micro <= max_micro
  }

  else(_) {
    fail
  }
}

