}

pub type BetDatum {
  bettor: ByteArray,
  target_price_raw: Int,
  target_exponent: Int,
  deadline_posix_ms: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  max_staleness_ms: Int,
}

pub type BetAction {
  ClaimWin
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp = if exponent < 0 { -exponent } else { exponent }
  lovelaces * raw_price / pow(10, abs_exp)
}

fn to_micro(raw_price: Int, exponent: Int) -> Int {
  let abs_exp = if exponent < 0 { -exponent } else { exponent }
  raw_price * 1_000_000 / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator price_bet {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect bet: BetDatum = raw_datum
    expect action: BetAction = redeemer

    // Obtener el oráculo de las entradas de referencia
    let oracle =
      get_oracle_datum(
        bet.oracle_policy,
        bet.oracle_asset,
        self.reference_inputs,
      )

    // Verificar frescura del dato del oráculo
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    expect upper - oracle.timestamp < bet.max_staleness_ms

    // Normalizar precios
    let current_micro = to_micro(oracle.price, oracle.exponent)
    let target_micro =
      to_micro(bet.target_price_raw, bet.target_exponent)

    when action is {
      ClaimWin -> {
        // El apostador reclama: precio actual >= objetivo Y apostador firmó
        let price_met = current_micro >= target_micro
        let signed = list.has(self.extra_signatories, bet.bettor)
        // Debe estar antes de la fecha límite
        let before_deadline = upper <= bet.deadline_posix_ms
        price_met && signed && before_deadline
      }
      Liquidate -> {
        // Liquidación: la fecha límite ya pasó sin alcanzar el precio
        expect IntervalBound { bound_type: Finite(lower), .. } =
          self.validity_range.lower_bound
        // El límite inferior de validez debe ser posterior a la fecha límite
        lower > bet.deadline_posix_ms
      }
    }
  }

  else(_) {
    fail
  }
}

