use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use cardano/address.{Address}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type SellOrderDatum {
  seller: ByteArray,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  trigger_price_raw: Int,
  max_age_ms: Int,
  payment_policy: PolicyId,
  payment_asset: AssetName,
  payment_amount: Int,
  seller_address: Address,
}

pub type SellAction {
  Cancel
  Fill
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn output_pays_seller(
  outputs: List<Output>,
  seller_address: Address,
  payment_policy: PolicyId,
  payment_asset: AssetName,
  payment_amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == seller_address && assets.quantity_of(
        o.value,
        payment_policy,
        payment_asset,
      ) >= payment_amount
    },
  )
}

validator limit_sell_order {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect datum: SellOrderDatum = raw_datum
    expect action: SellAction = redeemer
    when action is {
      Cancel -> list.has(self.extra_signatories, datum.seller)
      Fill -> {
        let oracle_datum =
          get_oracle_datum(
            datum.oracle_policy,
            datum.oracle_asset,
            self.reference_inputs,
          )
        // Staleness check
        expect IntervalBound { bound_type: Finite(upper), .. } =
          self.validity_range.upper_bound
        let is_fresh = upper - oracle_datum.timestamp < datum.max_age_ms
        expect is_fresh
        // Price must be at or above trigger (max_price sell condition)
        let price_triggered = oracle_datum.price >= datum.trigger_price_raw
        // Seller must be paid
        let seller_paid =
          output_pays_seller(
            self.outputs,
            datum.seller_address,
            datum.payment_policy,
            datum.payment_asset,
            datum.payment_amount,
          )
        price_triggered && seller_paid
      }
    }
  }
}

