use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use cardano/address.{Address}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type CdpDatum {
  owner: ByteArray,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  minted_debt: Int,
  min_collateral_ratio: Int,
  max_age_ms: Int,
  protocol_address: Address,
  debt_policy: PolicyId,
  debt_asset: AssetName,
}

pub type CdpAction {
  Repay
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

/// Calcula el ratio de salud: (valor_colateral * 100) / deuda_emitida
fn health_ratio(
  ada_lovelaces: Int,
  minted_debt: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_usd = compute_value(ada_lovelaces, raw_price, exponent)
  collateral_usd * 100 / minted_debt
}

fn find_output_to(
  outputs: List<Output>,
  target: Address,
  policy: PolicyId,
  asset: AssetName,
  min_amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == target && assets.quantity_of(o.value, policy, asset) >= min_amount
    },
  )
}

validator cdp_liquidation {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect datum: CdpDatum = raw_datum
    expect action: CdpAction = redeemer
    when action is {
      Repay -> list.has(self.extra_signatories, datum.owner)
      Liquidate -> {
        let oracle_datum =
          get_oracle_datum(
            datum.oracle_policy,
            datum.oracle_asset,
            self.reference_inputs,
          )
        // Verificación de frescura del oráculo
        expect IntervalBound { bound_type: Finite(upper), .. } =
          self.validity_range.upper_bound
        let is_fresh = upper - oracle_datum.timestamp < datum.max_age_ms
        expect is_fresh
        // Encontrar el UTxO que se está gastando para obtener el colateral bloqueado
        expect Some(spent_input) =
          list.find(self.inputs, fn(i) { i.output_reference == utxo })
        let locked_lovelaces = assets.lovelace_of(spent_input.output.value)
        // Ratio de salud debe estar por debajo del mínimo (precio cayó bajo el piso)
        let ratio =
          health_ratio(
            locked_lovelaces,
            datum.minted_debt,
            oracle_datum.price,
            oracle_datum.exponent,
          )
        let undercollateralized = ratio < datum.min_collateral_ratio
        // El liquidador debe devolver la deuda al protocolo
        let debt_returned =
          find_output_to(
            self.outputs,
            datum.protocol_address,
            datum.debt_policy,
            datum.debt_asset,
            datum.minted_debt,
          )
        undercollateralized && debt_returned
      }
    }
  }
}

