use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use cardano/address.{Address}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type AutoSellDatum {
  seller: ByteArray,
  seller_address: Address,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  max_price_trigger: Int,
  max_age_ms: Int,
  min_payment_lovelace: Int,
}

pub type AutoSellAction {
  Execute
  Withdraw
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn seller_receives_payment(
  outputs: List<Output>,
  seller_address: Address,
  min_lovelace: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == seller_address && assets.lovelace_of(o.value) >= min_lovelace
    },
  )
}

validator auto_sell {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect datum: AutoSellDatum = raw_datum
    expect action: AutoSellAction = redeemer
    when action is {
      Withdraw -> list.has(self.extra_signatories, datum.seller)
      Execute -> {
        let oracle_datum =
          get_oracle_datum(
            datum.oracle_policy,
            datum.oracle_asset,
            self.reference_inputs,
          )
        // Verificación de que el precio no está obsoleto
        expect IntervalBound { bound_type: Finite(upper), .. } =
          self.validity_range.upper_bound
        let is_fresh = upper - oracle_datum.timestamp < datum.max_age_ms
        expect is_fresh
        // El precio debe haber alcanzado o superado el precio objetivo de venta
        let price_reached = oracle_datum.price >= datum.max_price_trigger
        // El vendedor debe recibir el pago mínimo
        let payment_ok =
          seller_receives_payment(
            self.outputs,
            datum.seller_address,
            datum.min_payment_lovelace,
          )
        price_reached && payment_ok
      }
    }
  }
}

