use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// El datum almacena los parámetros de la posición colateralizada
pub type CollateralDatum {
  owner: ByteArray,
  locked_lovelaces: Int,
  minted_synth_amount: Int,
  min_health_ratio: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

/// Calcula el ratio de salud: (valor_colateral * 100) / deuda
/// Retorna un porcentaje entero, ej: 150 = 150%
fn health_ratio(
  locked_lovelaces: Int,
  minted_amount: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_value = compute_value(locked_lovelaces, raw_price, exponent)
  collateral_value * 100 / minted_amount
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator collateral_release {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect col_datum: CollateralDatum = raw_datum
    let oracle =
      get_oracle_datum(
        col_datum.oracle_policy,
        col_datum.oracle_asset,
        self.reference_inputs,
      )
    // Verificación de frescura: el oráculo debe estar dentro de 5 minutos
    let max_age_ms = 300_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms
    // Calcular el ratio de salud de la posición
    let current_health =
      health_ratio(
        col_datum.locked_lovelaces,
        col_datum.minted_synth_amount,
        oracle.price,
        oracle.exponent,
      )
    // Solo permitir liberación si la salud está POR ENCIMA del mínimo
    let health_ok = current_health >= col_datum.min_health_ratio
    // El propietario debe firmar
    let owner_signed =
      list.has(self.extra_signatories, col_datum.owner)
    is_fresh && health_ok && owner_signed
  }

  else(_) {
    fail
  }
}

