use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Datum del UTxO protegido con stop-loss y circuit breaker
pub type StopLossDatum {
  owner: ByteArray,
  threshold_price: Int,
  max_drop_bps: Int,
  reference_price: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

/// Calcula la caída porcentual en puntos base (bps)
/// drop_bps = (reference_price - current_price) * 10_000 / reference_price
/// 100 bps = 1%, 1000 bps = 10%
fn drop_in_bps(reference_price: Int, current_price: Int) -> Int {
  if current_price >= reference_price {
    0
  } else {
    (reference_price - current_price) * 10_000 / reference_price
  }
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator stop_loss_circuit_breaker {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect sl_datum: StopLossDatum = raw_datum
    let oracle =
      get_oracle_datum(
        sl_datum.oracle_policy,
        sl_datum.oracle_asset,
        self.reference_inputs,
      )
    // Verificar frescura del oráculo (máximo 5 minutos)
    let max_age_ms = 300_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms
    // Condición stop-loss: el precio debe estar POR DEBAJO del umbral
    let price_below_threshold = oracle.price < sl_datum.threshold_price
    // Circuit breaker: la caída no debe exceder max_drop_bps
    // Esto protege contra manipulación del oráculo o flash crashes
    let current_drop = drop_in_bps(sl_datum.reference_price, oracle.price)
    let within_circuit_breaker = current_drop <= sl_datum.max_drop_bps
    // El propietario debe firmar la transacción
    let owner_signed =
      list.has(self.extra_signatories, sl_datum.owner)
    is_fresh && price_below_threshold && within_circuit_breaker && owner_signed
  }

  else(_) {
    fail
  }
}

