use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}
use cardano/address.{Script}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type CDPDatum {
  owner: ByteArray,
  ada_locked: Int,
  synth_minted: Int,
}

pub type Action {
  Mint
  Burn
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn health_ratio(
  ada_locked: Int,
  minted: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_locked * raw_price / pow(10, abs_exp) * 100 / minted
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator cdp_v1(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  collateral_ratio: Int,
  liquidation_threshold: Int,
  max_age_ms: Int,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp_datum: CDPDatum = raw_datum
    expect action: Action = redeemer
    let oracle =
      get_oracle_datum(oracle_policy, oracle_asset, self.reference_inputs)
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms
    expect is_fresh
    when action is {
      Mint -> {
        let continuing_output =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(d) -> {
                  expect new_cdp: CDPDatum = d
                  new_cdp.owner == cdp_datum.owner
                }
                _ -> False
              }
            },
          )
        expect Some(cont_out) = continuing_output
        expect InlineDatum(cont_raw) = cont_out.datum
        expect new_cdp: CDPDatum = cont_raw
        let ada_deposited = new_cdp.ada_locked - cdp_datum.ada_locked
        let new_synth = new_cdp.synth_minted - cdp_datum.synth_minted
        let max_mintable =
          compute_value(ada_deposited, oracle.price, oracle.exponent) * 100 / collateral_ratio
        ada_deposited >= 1_000_000 && new_synth <= max_mintable && new_synth > 0 && list.has(
          self.extra_signatories,
          cdp_datum.owner,
        )
      }
      Burn -> {
        let owner_signed =
          list.has(self.extra_signatories, cdp_datum.owner)
        expect owner_signed
        let continuing_output =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(d) -> {
                  expect new_cdp: CDPDatum = d
                  new_cdp.owner == cdp_datum.owner
                }
                _ -> False
              }
            },
          )
        expect Some(cont_out) = continuing_output
        expect InlineDatum(cont_raw) = cont_out.datum
        expect new_cdp: CDPDatum = cont_raw
        let synth_burned = cdp_datum.synth_minted - new_cdp.synth_minted
        synth_burned > 0 && new_cdp.ada_locked >= 0 && new_cdp.synth_minted >= 0
      }
      Liquidate -> {
        let ratio =
          health_ratio(
            cdp_datum.ada_locked,
            cdp_datum.synth_minted,
            oracle.price,
            oracle.exponent,
          )
        ratio < liquidation_threshold
      }
    }
  }
}

