use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}
use cardano/address.{Script}

/// Dato del oráculo con precio, exponente y marca temporal
pub type DatoOraculo {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Dato de la posición CDP: dueño, ADA bloqueado y synth acuñado
pub type DatoCDP {
  dueno: ByteArray,
  ada_bloqueado: Int,
  synth_acunado: Int,
}

/// Acciones disponibles en el contrato
pub type Accion {
  Mint
  Burn
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn calcular_valor(
  ada_lovelaces: Int,
  precio_raw: Int,
  exponente: Int,
) -> Int {
  let abs_exp =
    if exponente < 0 {
      -exponente
    } else {
      exponente
    }
  ada_lovelaces * precio_raw / pow(10, abs_exp)
}

fn ratio_salud(
  ada_bloqueado: Int,
  acunado: Int,
  precio_raw: Int,
  exponente: Int,
) -> Int {
  let abs_exp =
    if exponente < 0 {
      -exponente
    } else {
      exponente
    }
  ada_bloqueado * precio_raw / pow(10, abs_exp) * 100 / acunado
}

fn obtener_dato_oraculo(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> DatoOraculo {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect dato: DatoOraculo = raw
  dato
}

validator cdp_v2(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ratio_colateral: Int,
  umbral_liquidacion: Int,
  edad_maxima_ms: Int,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(dato_raw) = datum
    expect cdp: DatoCDP = dato_raw
    expect accion: Accion = redeemer
    let oraculo =
      obtener_dato_oraculo(
        oracle_policy,
        oracle_asset,
        self.reference_inputs,
      )
    // Verificar frescura del precio
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let fresco = upper - oraculo.timestamp < edad_maxima_ms
    expect fresco
    when accion is {
      Mint -> {
        // El dueño debe firmar para acuñar
        expect list.has(self.extra_signatories, cdp.dueno)
        // Buscar salida continuante con nuevo CDP
        expect Some(salida_cont) =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(d) -> {
                  expect nuevo: DatoCDP = d
                  nuevo.dueno == cdp.dueno
                }
                _ -> False
              }
            },
          )
        expect InlineDatum(raw_cont) = salida_cont.datum
        expect nuevo_cdp: DatoCDP = raw_cont
        let ada_depositado = nuevo_cdp.ada_bloqueado - cdp.ada_bloqueado
        let synth_nuevo = nuevo_cdp.synth_acunado - cdp.synth_acunado
        let max_acunable =
          calcular_valor(ada_depositado, oraculo.price, oraculo.exponent) * 100 / ratio_colateral
        ada_depositado >= 1_000_000 && synth_nuevo > 0 && synth_nuevo <= max_acunable
      }
      Burn -> {
        expect list.has(self.extra_signatories, cdp.dueno)
        expect Some(salida_cont) =
          list.find(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(d) -> {
                  expect nuevo: DatoCDP = d
                  nuevo.dueno == cdp.dueno
                }
                _ -> False
              }
            },
          )
        expect InlineDatum(raw_cont) = salida_cont.datum
        expect nuevo_cdp: DatoCDP = raw_cont
        let quemado = cdp.synth_acunado - nuevo_cdp.synth_acunado
        quemado > 0 && nuevo_cdp.ada_bloqueado >= 0 && nuevo_cdp.synth_acunado >= 0
      }
      Liquidate -> {
        // Cualquiera puede liquidar si el ratio está por debajo del umbral
        let ratio =
          ratio_salud(
            cdp.ada_bloqueado,
            cdp.synth_acunado,
            oraculo.price,
            oraculo.exponent,
          )
        ratio < umbral_liquidacion
      }
    }
  }
}

