use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}
use cardano/address.{Script, Address}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type CDPDatum {
  owner: ByteArray,
  ada_locked: Int,
  synth_minted: Int,
}

pub type Action {
  Mint
  Burn
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn health_ratio(
  ada_locked: Int,
  minted: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_locked * raw_price / pow(10, abs_exp) * 100 / minted
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn find_continuing_cdp(
  outputs: List<Output>,
  owner: ByteArray,
) -> CDPDatum {
  expect Some(cont_out) =
    list.find(
      outputs,
      fn(o) {
        when o.datum is {
          InlineDatum(d) -> {
            expect cdp: CDPDatum = d
            cdp.owner == owner
          }
          _ -> False
        }
      },
    )
  expect InlineDatum(cont_raw) = cont_out.datum
  expect new_cdp: CDPDatum = cont_raw
  new_cdp
}

validator cdp_advanced(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  collateral_ratio: Int,
  liquidation_threshold: Int,
  max_age_ms: Int,
  synth_policy: PolicyId,
  synth_asset: AssetName,
) {
  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect cdp: CDPDatum = raw_datum
    expect action: Action = redeemer
    let oracle =
      get_oracle_datum(oracle_policy, oracle_asset, self.reference_inputs)
    // Freshness check
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    expect upper - oracle.timestamp < max_age_ms
    when action is {
      Mint -> {
        expect list.has(self.extra_signatories, cdp.owner)
        let new_cdp = find_continuing_cdp(self.outputs, cdp.owner)
        let ada_deposited = new_cdp.ada_locked - cdp.ada_locked
        let synth_delta = new_cdp.synth_minted - cdp.synth_minted
        let max_mintable =
          compute_value(ada_deposited, oracle.price, oracle.exponent) * 100 / collateral_ratio
        // Verify synth tokens are actually minted in the transaction
        let minted_synth =
          assets.quantity_of(self.mint, synth_policy, synth_asset)
        ada_deposited >= 1_000_000 && synth_delta > 0 && synth_delta <= max_mintable && minted_synth == synth_delta
      }
      Burn -> {
        expect list.has(self.extra_signatories, cdp.owner)
        let new_cdp = find_continuing_cdp(self.outputs, cdp.owner)
        let synth_burned = cdp.synth_minted - new_cdp.synth_minted
        // Verify synth tokens are actually burned (negative mint)
        let burned_in_tx =
          assets.quantity_of(self.mint, synth_policy, synth_asset)
        synth_burned > 0 && burned_in_tx == -synth_burned && new_cdp.synth_minted >= 0 && new_cdp.ada_locked >= 0
      }
      Liquidate -> {
        let ratio =
          health_ratio(
            cdp.ada_locked,
            cdp.synth_minted,
            oracle.price,
            oracle.exponent,
          )
        // Anyone can liquidate undercollateralized positions
        // Liquidator must burn the synth debt
        let burned_in_tx =
          assets.quantity_of(self.mint, synth_policy, synth_asset)
        ratio < liquidation_threshold && burned_in_tx == -cdp.synth_minted
      }
    }
  }
}

