use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}
use cardano/address.{Script, Address}

/// Dato del oráculo: precio, exponente y marca temporal POSIX
pub type DatoOraculo {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Dato de posición CDP
pub type DatoPosicion {
  propietario: ByteArray,
  ada_bloqueado: Int,
  synth_emitido: Int,
}

/// Acciones del validador de gasto
pub type Accion {
  Mint
  Burn
  Liquidate
}

/// Acciones de la política de acuñación
pub type AccionMint {
  Acunar
  Quemar
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn calcular_valor(
  ada_lovelaces: Int,
  precio_raw: Int,
  exponente: Int,
) -> Int {
  let abs_exp =
    if exponente < 0 {
      -exponente
    } else {
      exponente
    }
  ada_lovelaces * precio_raw / pow(10, abs_exp)
}

fn ratio_salud(
  ada_bloqueado: Int,
  emitido: Int,
  precio_raw: Int,
  exponente: Int,
) -> Int {
  let abs_exp =
    if exponente < 0 {
      -exponente
    } else {
      exponente
    }
  ada_bloqueado * precio_raw / pow(10, abs_exp) * 100 / emitido
}

fn obtener_oraculo(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> DatoOraculo {
  expect Some(entrada_oraculo) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = entrada_oraculo.output.datum
  expect dato: DatoOraculo = raw
  dato
}

fn verificar_frescura(tx: Transaction, timestamp_oraculo: Int, edad_maxima: Int) -> Bool {
  expect IntervalBound { bound_type: Finite(upper), .. } =
    tx.validity_range.upper_bound
  upper - timestamp_oraculo < edad_maxima
}

fn buscar_posicion_continuante(
  salidas: List<Output>,
  propietario: ByteArray,
) -> DatoPosicion {
  expect Some(salida) =
    list.find(
      salidas,
      fn(o) {
        when o.datum is {
          InlineDatum(d) -> {
            expect pos: DatoPosicion = d
            pos.propietario == propietario
          }
          _ -> False
        }
      },
    )
  expect InlineDatum(raw) = salida.datum
  expect pos: DatoPosicion = raw
  pos
}

validator cdp_completo(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ratio_colateral: Int,
  umbral_liquidacion: Int,
  edad_maxima_ms: Int,
  script_cdp: ByteArray,
) {
  mint(
    redeemer: Data,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    expect accion_mint: AccionMint = redeemer
    let oraculo =
      obtener_oraculo(oracle_policy, oracle_asset, self.reference_inputs)
    expect verificar_frescura(self, oraculo.timestamp, edad_maxima_ms)
    when accion_mint is {
      Acunar -> {
        // Verificar que hay una salida al script CDP con dato válido
        expect Some(salida_cdp) =
          list.find(
            self.outputs,
            fn(o) {
              when o.address.payment_credential is {
                Script(hash) -> hash == script_cdp
                _ -> False
              }
            },
          )
        expect InlineDatum(raw) = salida_cdp.datum
        expect pos: DatoPosicion = raw
        // El ADA bloqueado debe respaldar la emisión al ratio requerido
        let valor_colateral =
          calcular_valor(pos.ada_bloqueado, oraculo.price, oraculo.exponent)
        let min_colateral = pos.synth_emitido * ratio_colateral / 100
        // Verificar que los tokens acuñados coinciden
        let tokens_acunados =
          assets.quantity_of(
            self.mint,
            policy_id,
            #"73796e7468",
          )
        valor_colateral >= min_colateral && tokens_acunados == pos.synth_emitido && tokens_acunados > 0
      }
      Quemar -> {
        // Para quemar, verificar que la cantidad es negativa
        let tokens_quemados =
          assets.quantity_of(
            self.mint,
            policy_id,
            #"73796e7468",
          )
        tokens_quemados < 0
      }
    }
  }

  spend(
    datum: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(dato_raw) = datum
    expect posicion: DatoPosicion = dato_raw
    expect accion: Accion = redeemer
    let oraculo =
      obtener_oraculo(oracle_policy, oracle_asset, self.reference_inputs)
    expect verificar_frescura(self, oraculo.timestamp, edad_maxima_ms)
    when accion is {
      Mint -> {
        expect list.has(self.extra_signatories, posicion.propietario)
        let nueva_pos =
          buscar_posicion_continuante(self.outputs, posicion.propietario)
        let ada_nuevo = nueva_pos.ada_bloqueado - posicion.ada_bloqueado
        let synth_nuevo = nueva_pos.synth_emitido - posicion.synth_emitido
        let max_acunable =
          calcular_valor(ada_nuevo, oraculo.price, oraculo.exponent) * 100 / ratio_colateral
        ada_nuevo >= 1_000_000 && synth_nuevo > 0 && synth_nuevo <= max_acunable
      }
      Burn -> {
        expect list.has(self.extra_signatories, posicion.propietario)
        let nueva_pos =
          buscar_posicion_continuante(self.outputs, posicion.propietario)
        let quemado = posicion.synth_emitido - nueva_pos.synth_emitido
        quemado > 0 && nueva_pos.synth_emitido >= 0
      }
      Liquidate -> {
        let ratio =
          ratio_salud(
            posicion.ada_bloqueado,
            posicion.synth_emitido,
            oraculo.price,
            oraculo.exponent,
          )
        ratio < umbral_liquidacion
      }
    }
  }
}

