use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use cardano/address.{Address, Script}
use aiken/interval.{Finite, IntervalBound}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type VaultDatum {
  owner: ByteArray,
  minted_synth: Int,
}

pub type VaultConfig {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  min_collateral_ratio: Int,
  max_staleness_ms: Int,
  vault_script_hash: ByteArray,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

/// Calcula la ratio de salud como porcentaje entero.
/// health_ratio = (ada_locked_value_usd * 100) / minted_synth
/// Ejemplo: 150 significa 150% de colateralización.
fn health_ratio(
  ada_lovelaces: Int,
  minted_synth: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_usd = compute_value(ada_lovelaces, raw_price, exponent)
  collateral_usd * 100 / minted_synth
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

validator cdp_vault(config: VaultConfig) {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    // Extraer el datum de la bóveda
    expect Some(raw_datum) = datum
    expect vault_datum: VaultDatum = raw_datum

    // Obtener el dato del oráculo desde las entradas de referencia
    let oracle =
      get_oracle_datum(
        config.oracle_policy,
        config.oracle_asset,
        self.reference_inputs,
      )

    // Verificar frescura del oráculo
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let es_fresco = upper - oracle.timestamp < config.max_staleness_ms

    // Verificar que el propietario firmó la transacción
    let firmado_por_propietario =
      list.has(self.extra_signatories, vault_datum.owner)

    // Encontrar la salida continua de la bóveda (debe volver al mismo script)
    expect Some(salida_continuacion) =
      list.find(
        self.outputs,
        fn(o) {
          o.address.payment_credential == Script(config.vault_script_hash)
        },
      )

    // Extraer el datum de continuación de la bóveda
    expect InlineDatum(raw_cont) = salida_continuacion.datum
    expect vault_cont: VaultDatum = raw_cont

    // Calcular la ratio de salud del colateral restante
    let ada_restante = assets.lovelace_of(salida_continuacion.value)
    let ratio =
      health_ratio(
        ada_restante,
        vault_cont.minted_synth,
        oracle.price,
        oracle.exponent,
      )

    // La ratio debe mantenerse por encima del mínimo requerido
    let ratio_ok = ratio >= config.min_collateral_ratio

    // La deuda no puede aumentar
    let deuda_ok = vault_cont.minted_synth <= vault_datum.minted_synth

    es_fresco && firmado_por_propietario && ratio_ok && deuda_ok
  }

  else(_) {
    fail
  }
}

