use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type BuyOrderDatum {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  max_price: Int,
  max_age_ms: Int,
  buyer: ByteArray,
}

pub type BuyAction {
  Execute
  Cancel
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

/// Normalize price to micro-units per 1 ADA (1_000_000 lovelace)
fn normalize_price(raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  raw_price * 1_000_000 / pow(10, abs_exp)
}

validator limit_buy_order {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect order: BuyOrderDatum = raw_datum
    expect action: BuyAction = redeemer
    when action is {
      Cancel -> {
        // Only the buyer can cancel
        list.has(self.extra_signatories, order.buyer)
      }
      Execute -> {
        let oracle =
          get_oracle_datum(
            order.oracle_policy,
            order.oracle_asset,
            self.reference_inputs,
          )
        // Staleness check
        expect IntervalBound { bound_type: Finite(upper), .. } =
          self.validity_range.upper_bound
        let is_fresh = upper - oracle.timestamp < order.max_age_ms
        // Price must be at or below max_price (buyer wants low price)
        let current_price =
          normalize_price(oracle.price, oracle.exponent)
        let price_ok = current_price <= order.max_price
        // Buyer must sign the execution
        let signed = list.has(self.extra_signatories, order.buyer)
        is_fresh && price_ok && signed
      }
    }
  }

  else(_) {
    fail
  }
}

