use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

pub type OrdenVentaDatum {
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  precio_objetivo: Int,
  max_antiguedad_ms: Int,
  vendedor: ByteArray,
}

pub type AccionVenta {
  Ejecutar
  Cancelar
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

fn normalizar_precio(raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  raw_price * 1_000_000 / pow(10, abs_exp)
}

validator orden_venta_automatica {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect orden: OrdenVentaDatum = raw_datum
    expect accion: AccionVenta = redeemer
    when accion is {
      Cancelar -> {
        // Solo el vendedor puede cancelar la orden
        list.has(self.extra_signatories, orden.vendedor)
      }
      Ejecutar -> {
        let oracle =
          get_oracle_datum(
            orden.oracle_policy,
            orden.oracle_asset,
            self.reference_inputs,
          )
        // Verificación de frescura: datos del oráculo no pueden ser obsoletos
        expect IntervalBound { bound_type: Finite(upper), .. } =
          self.validity_range.upper_bound
        let is_fresh =
          upper - oracle.timestamp < orden.max_antiguedad_ms
        // El precio actual debe ser mayor o igual al precio objetivo
        let precio_actual =
          normalizar_precio(oracle.price, oracle.exponent)
        let precio_cumple = precio_actual >= orden.precio_objetivo
        // El vendedor debe firmar la ejecución
        let firmado =
          list.has(self.extra_signatories, orden.vendedor)
        // Verificar que los ADA van al vendedor: al menos un output
        // debe ir a una dirección que contenga la clave del vendedor
        expect Some(spent_input) =
          list.find(self.inputs, fn(i) { i.output_reference == utxo })
        let ada_en_orden =
          assets.lovelace_of(spent_input.output.value)
        let valor_usd =
          compute_value(ada_en_orden, oracle.price, oracle.exponent)
        // Todas las condiciones deben cumplirse
        is_fresh && precio_cumple && firmado && valor_usd > 0
      }
    }
  }

  else(_) {
    fail
  }
}

