use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Datum para posiciones de colateral
/// min_health_ratio: porcentaje mínimo de salud (ej. 150 = 150%)
/// minted_amount: cantidad de synth acuñada en micro-unidades
pub type CollateralDatum {
  owner: ByteArray,
  minted_amount: Int,
  min_health_ratio: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

/// Calcula el ratio de salud como porcentaje entero
/// health = (collateral_value * 100) / minted_amount
fn health_ratio(
  ada_lovelaces: Int,
  minted_amount: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let collateral_usd = compute_value(ada_lovelaces, raw_price, exponent)
  collateral_usd * 100 / minted_amount
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

/// Obtiene el total de lovelaces del UTxO que se está gastando
fn get_spent_utxo_lovelaces(
  utxo: OutputReference,
  inputs: List<Input>,
) -> Int {
  expect Some(spent_input) =
    list.find(inputs, fn(i) { i.output_reference == utxo })
  assets.lovelace_of(spent_input.output.value)
}

validator collateral_release {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect col_datum: CollateralDatum = raw_datum

    let oracle =
      get_oracle_datum(
        col_datum.oracle_policy,
        col_datum.oracle_asset,
        self.reference_inputs,
      )

    // Verificación de frescura: máximo 5 minutos
    let max_age_ms = 300_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms

    // Obtener lovelaces del UTxO colateral
    let locked_lovelaces = get_spent_utxo_lovelaces(utxo, self.inputs)

    // Calcular ratio de salud
    let current_health =
      health_ratio(
        locked_lovelaces,
        col_datum.minted_amount,
        oracle.price,
        oracle.exponent,
      )

    // Solo permitir liberar si la salud está POR ENCIMA del mínimo
    let health_sufficient = current_health >= col_datum.min_health_ratio

    // El dueño debe firmar
    let owner_signed =
      list.has(self.extra_signatories, col_datum.owner)

    is_fresh && health_sufficient && owner_signed
  }

  else(_) {
    fail
  }
}

