use aiken/collection/list
use aiken/interval.{Finite, IntervalBound}
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}

pub type OracleDatum {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Datum de gasto con umbral de precio
/// threshold_price: precio mínimo aceptable (mismo formato que oracle.price)
/// Si el precio cae por debajo, se permite retirar los fondos
pub type SpendDatum {
  owner: ByteArray,
  threshold_price: Int,
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn get_oracle_datum(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> OracleDatum {
  expect Some(oracle_input) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = oracle_input.output.datum
  expect datum: OracleDatum = raw
  datum
}

/// Encuentra el UTxO que se está gastando y retorna sus lovelaces
fn find_spent_lovelaces(
  utxo: OutputReference,
  inputs: List<Input>,
) -> Int {
  expect Some(input) =
    list.find(inputs, fn(i) { i.output_reference == utxo })
  assets.lovelace_of(input.output.value)
}

validator stop_loss_band {
  spend(
    datum: Option<Data>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum
    expect spend_datum: SpendDatum = raw_datum

    let oracle =
      get_oracle_datum(
        spend_datum.oracle_policy,
        spend_datum.oracle_asset,
        self.reference_inputs,
      )

    // Verificación de frescura del oráculo: máximo 4 minutos
    let max_age_ms = 240_000
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let is_fresh = upper - oracle.timestamp < max_age_ms

    // Obtener lovelaces bloqueados en el UTxO
    let locked_lovelaces = find_spent_lovelaces(utxo, self.inputs)

    // Calcular valor actual en USD del colateral
    let current_usd_value =
      compute_value(locked_lovelaces, oracle.price, oracle.exponent)

    // Calcular valor umbral en USD (usando los mismos lovelaces)
    let threshold_usd_value =
      compute_value(
        locked_lovelaces,
        spend_datum.threshold_price,
        oracle.exponent,
      )

    // Stop-loss: permitir gastar solo si el valor actual
    // cayó por debajo del valor umbral
    let stop_loss_triggered = current_usd_value < threshold_usd_value

    // El dueño debe firmar la transacción
    let owner_signed =
      list.has(self.extra_signatories, spend_datum.owner)

    is_fresh && stop_loss_triggered && owner_signed
  }

  else(_) {
    fail
  }
}

