use aiken/collection/list
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction, Input, Output, OutputReference, InlineDatum}
use aiken/interval.{Finite, IntervalBound}

/// Datos del oráculo: precio bruto, exponente y marca temporal POSIX
pub type DatosOraculo {
  price: Int,
  exponent: Int,
  timestamp: Int,
}

/// Datos de la posición de deuda colateral
pub type DatosCdp {
  propietario: ByteArray,
  ada_bloqueado: Int,
  sintetico_acunado: Int,
}

/// Acciones posibles sobre la posición
pub type Action {
  Mint
  Burn
  Liquidate
}

fn pow(base: Int, exp: Int) -> Int {
  if exp == 0 {
    1
  } else {
    base * pow(base, exp - 1)
  }
}

fn compute_value(ada_lovelaces: Int, raw_price: Int, exponent: Int) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_lovelaces * raw_price / pow(10, abs_exp)
}

fn health_ratio(
  ada_locked: Int,
  minted: Int,
  raw_price: Int,
  exponent: Int,
) -> Int {
  let abs_exp =
    if exponent < 0 {
      -exponent
    } else {
      exponent
    }
  ada_locked * raw_price / pow(10, abs_exp) * 100 / minted
}

fn obtener_datos_oraculo(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ref_inputs: List<Input>,
) -> DatosOraculo {
  expect Some(entrada_oraculo) =
    list.find(
      ref_inputs,
      fn(i) {
        assets.quantity_of(i.output.value, oracle_policy, oracle_asset) == 1
      },
    )
  expect InlineDatum(raw) = entrada_oraculo.output.datum
  expect datos: DatosOraculo = raw
  datos
}

validator cdp_sintetico(
  oracle_policy: PolicyId,
  oracle_asset: AssetName,
  ratio_colateral: Int,
  umbral_liquidacion: Int,
  max_edad_ms: Int,
) {
  spend(
    datum_opt: Option<Data>,
    redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(raw_datum) = datum_opt
    expect cdp: DatosCdp = raw_datum
    expect accion: Action = redeemer
    let oraculo =
      obtener_datos_oraculo(
        oracle_policy,
        oracle_asset,
        self.reference_inputs,
      )
    // Verificar frescura del oráculo
    expect IntervalBound { bound_type: Finite(upper), .. } =
      self.validity_range.upper_bound
    let oraculo_fresco = upper - oraculo.timestamp < max_edad_ms
    expect oraculo_fresco
    when accion is {
      Mint -> {
        // El propietario debe firmar para abrir/ampliar posición
        let firmado =
          list.has(self.extra_signatories, cdp.propietario)
        // Calcular el máximo de sintéticos permitidos dado el ADA bloqueado
        let valor_colateral =
          compute_value(
            cdp.ada_bloqueado,
            oraculo.price,
            oraculo.exponent,
          )
        let max_sintetico = valor_colateral * 100 / ratio_colateral
        // Verificar que lo acuñado no exceda el máximo
        firmado && cdp.sintetico_acunado <= max_sintetico && cdp.ada_bloqueado > 0
      }
      Burn -> {
        // Solo el propietario puede quemar y recuperar ADA
        let firmado =
          list.has(self.extra_signatories, cdp.propietario)
        firmado && cdp.sintetico_acunado >= 0
      }
      Liquidate -> {
        // Cualquiera puede liquidar si el ratio de salud está bajo el umbral
        let hr =
          health_ratio(
            cdp.ada_bloqueado,
            cdp.sintetico_acunado,
            oraculo.price,
            oraculo.exponent,
          )
        hr < umbral_liquidacion
      }
    }
  }
}

